template:
const std = @import("std");
const Allocator = std.mem.Allocator;

pub const MemoryPool = struct {
    memory: []u8,
    block_size: usize,
    block_count: usize,
    free_list: []bool,
    allocator: Allocator,

    pub fn init(block_size: usize, block_count: usize) !MemoryPool {
        var gpa = [[SLOT dbg_alloc]];
        const allocator = gpa.allocator();

        const aligned_size = [[SLOT align_call]];
        const memory = try allocator.alloc(u8, aligned_size * block_count);
        const free_list = try allocator.alloc(bool, block_count);

        for (free_list) |*slot| {
            [[SLOT slot_init]]
        }

        return MemoryPool{
            .memory = memory,
            .block_size = aligned_size,
            .block_count = block_count,
            .free_list = free_list,
            .allocator = allocator,
        };
    }

    pub fn alloc(self: *MemoryPool) ?*anyopaque {
        for (self.free_list, 0..) |is_free, i| {
            if (is_free) {
                self.free_list[i] = false;
                const offset = i * self.block_size;
                return @ptrCast(&self.memory[offset]);
            }
        }
        return null;
    }

    pub fn free(self: *MemoryPool, ptr: *anyopaque) !void {
        const ptr_addr = @intFromPtr(ptr);
        const base_addr = @intFromPtr(self.memory.ptr);

        if ([[SLOT bound_check]]) {
            return error.InvalidPointer;
        }

        const offset = ptr_addr - base_addr;
        if (offset % self.block_size != 0) {
            return error.InvalidPointer;
        }

        const index = offset / self.block_size;
        if (index >= self.block_count) {
            return error.InvalidPointer;
        }

        if (self.free_list[index]) {
            return error.DoubleFree;
        }

        self.free_list[index] = true;
    }

    pub fn available(self: *const MemoryPool) usize {
        var count: usize = 0;
        for (self.free_list) |is_free| {
            if (is_free) count += 1;
        }
        return count;
    }

    pub fn deinit(self: *MemoryPool) void {
        self.allocator.free(self.memory);
        self.allocator.free(self.free_list);
    }
};
